package node

// validate.go — emits _validators.ts when EmitOptions.Validate is true.
//
// The generated file contains zero-dependency runtime validators:
//   - VeldContractError   — thrown on output shape violation  (→ HTTP 500)
//   - VeldValidationError — thrown on input parsing failure   (→ HTTP 400)
//   - assertX()           — asserts output shape matches contract model
//   - assertXArray()      — asserts output is an array of model (when needed)
//   - parseX()            — parses + validates request input model
//
// All functions are generated as flat, specific code — no generic schema
// traversal at runtime. This is equivalent to "precompiled validators".

import (
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"

	"github.com/Adhamzineldin/Veld/internal/ast"
)

// emitValidators writes generated/_validators.ts with zero-dep runtime validators.
func (e *NodeEmitter) emitValidators(a ast.AST, outDir string) error {
	var sb strings.Builder

	sb.WriteString("// AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n")
	sb.WriteString("// Runtime contract validators \u2014 zero external dependencies\n")
	sb.WriteString("//\n")
	sb.WriteString("// assertX()      \u2014 output shape guard     \u2192 throws VeldContractError   (HTTP 500)\n")
	sb.WriteString("// assertXArray() \u2014 output array guard     \u2192 throws VeldContractError   (HTTP 500)\n")
	sb.WriteString("// parseX()       \u2014 input parser/validator \u2192 throws VeldValidationError (HTTP 400)\n")
	sb.WriteString("\n")

	// Re-export types so callers can use the type narrowing.
	sb.WriteString("import type * as Types from './types/index';\n\n")

	// ── Error classes ─────────────────────────────────────────────────────────
	sb.WriteString(tsErrorClasses)
	sb.WriteString("\n")

	// ── Gather metadata needed for generation ─────────────────────────────────
	byName := modelsByName(a.Models)
	enumNames := enumSet(a.Enums)
	arrayOutputModels := collectArrayOutputModels(a)
	inputModels := collectInputModels(a)

	// ── Emit assertX / assertXArray — topologically sorted ───────────────────
	sorted := topoSortModels(a.Models)
	for _, model := range sorted {
		writeNodeAssertFunc(&sb, model, byName, enumNames)
		sb.WriteString("\n")
		if arrayOutputModels[model.Name] {
			writeNodeAssertArrayFunc(&sb, model)
			sb.WriteString("\n")
		}
	}

	// ── Emit parseX — only for models used as action inputs ──────────────────
	for _, model := range sorted {
		if inputModels[model.Name] {
			writeNodeParseFunc(&sb, model, byName, enumNames)
			sb.WriteString("\n")
		}
	}

	return os.WriteFile(filepath.Join(outDir, "_validators.ts"), []byte(sb.String()), 0644)
}

// ── Template: error classes ───────────────────────────────────────────────────

const tsErrorClasses = `// ── Error Types ──────────────────────────────────────────────────────────────

/** Thrown when a service returns a response that violates the contract shape (→ HTTP 500). */
export class VeldContractError extends Error {
  readonly field: string;
  readonly expected: string;
  readonly status = 500 as const;

  constructor(field: string, expected: string, actual: unknown) {
    const got = actual === null ? 'null' : Array.isArray(actual) ? 'array' : typeof actual;
    super(` + "`" + `Contract violation \u2014 ${field}: expected ${expected}, got ${got}` + "`" + `);
    this.name = 'VeldContractError';
    this.field = field;
    this.expected = expected;
  }
}

/** Thrown when request input fails shape validation (→ HTTP 400). */
export class VeldValidationError extends Error {
  readonly errors: string[];
  readonly status = 400 as const;
  readonly code = 'VALIDATION_ERROR' as const;

  constructor(errors: string[]) {
    super('Validation failed: ' + errors.join('; '));
    this.name = 'VeldValidationError';
    this.errors = errors;
  }
}

`

// ── assertX ───────────────────────────────────────────────────────────────────

// writeNodeAssertFunc generates an assertX() function that guards output shape.
// Parents are called first (via their own assertX), then own fields are checked.
func writeNodeAssertFunc(sb *strings.Builder, model ast.Model, byName map[string]ast.Model, enumNames map[string]bool) {
	fnName := "assert" + model.Name
	sb.WriteString(fmt.Sprintf("/** Asserts data matches the %s contract shape. Throws VeldContractError (\u2192 500) on mismatch. */\n", model.Name))
	sb.WriteString(fmt.Sprintf("export function %s(data: unknown, path = '%s'): asserts data is Types.%s {\n", fnName, model.Name, model.Name))
	sb.WriteString("  if (data === null || typeof data !== 'object' || Array.isArray(data))\n")
	sb.WriteString("    throw new VeldContractError(path, 'object', data);\n")

	// Delegate parent field validation to the parent assert (DRY, avoids duplication).
	if model.Extends != "" {
		sb.WriteString(fmt.Sprintf("  assert%s(data, path);\n", model.Extends))
	}

	if len(model.Fields) > 0 {
		sb.WriteString("  const d = data as Record<string, unknown>;\n")
		for _, field := range model.Fields {
			writeNodeAssertField(sb, field, byName, enumNames)
		}
	}

	sb.WriteString("}\n")
}

// writeNodeAssertField emits the per-field check inside an assertX function.
func writeNodeAssertField(sb *strings.Builder, field ast.Field, byName map[string]ast.Model, enumNames map[string]bool) {
	key := fmt.Sprintf("d['%s']", field.Name)
	pathExpr := fmt.Sprintf("`${path}.%s`", field.Name)

	if field.Optional {
		writeNodeAssertFieldOptional(sb, field, key, pathExpr, byName, enumNames)
	} else {
		writeNodeAssertFieldRequired(sb, field, key, pathExpr, byName, enumNames)
	}
}

func writeNodeAssertFieldRequired(sb *strings.Builder, field ast.Field, key, pathExpr string, byName map[string]ast.Model, enumNames map[string]bool) {
	switch {
	case len(field.UnionTypes) > 0:
		// Union types are compile-time checked by TypeScript — skip deep runtime check.
		sb.WriteString(fmt.Sprintf("  if (%s === undefined || %s === null)\n", key, key))
		sb.WriteString(fmt.Sprintf("    throw new VeldContractError(%s, 'union value', %s);\n", pathExpr, key))

	case field.IsArray:
		sb.WriteString(fmt.Sprintf("  if (!Array.isArray(%s))\n", key))
		sb.WriteString(fmt.Sprintf("    throw new VeldContractError(%s, 'array', %s);\n", pathExpr, key))
		// Recursively assert each element for model arrays.
		if _, isModel := byName[field.Type]; isModel {
			sb.WriteString(fmt.Sprintf("  for (let _i = 0; _i < (%s as unknown[]).length; _i++)\n", key))
			sb.WriteString(fmt.Sprintf("    assert%s((%s as unknown[])[_i], `${path}.%s[${_i}]`);\n", field.Type, key, field.Name))
		}

	case field.IsMap:
		sb.WriteString(fmt.Sprintf("  if (typeof %s !== 'object' || %s === null || Array.isArray(%s))\n", key, key, key))
		sb.WriteString(fmt.Sprintf("    throw new VeldContractError(%s, 'Record', %s);\n", pathExpr, key))

	default:
		if _, isModel := byName[field.Type]; isModel {
			// Nested model — delegate to its assertX function.
			sb.WriteString(fmt.Sprintf("  assert%s(%s, %s);\n", field.Type, key, pathExpr))
		} else {
			expected := tsScalarExpected(field.Type)
			sb.WriteString(fmt.Sprintf("  if (typeof %s !== '%s')\n", key, expected))
			sb.WriteString(fmt.Sprintf("    throw new VeldContractError(%s, '%s', %s);\n", pathExpr, expected, key))
		}
	}
}

func writeNodeAssertFieldOptional(sb *strings.Builder, field ast.Field, key, pathExpr string, byName map[string]ast.Model, enumNames map[string]bool) {
	present := fmt.Sprintf("%s !== undefined && %s !== null", key, key)

	switch {
	case len(field.UnionTypes) > 0:
		// Union types — compile-time only, no runtime check needed for optional fields.

	case field.IsArray:
		sb.WriteString(fmt.Sprintf("  if (%s && !Array.isArray(%s))\n", present, key))
		sb.WriteString(fmt.Sprintf("    throw new VeldContractError(%s, 'array | undefined', %s);\n", pathExpr, key))
		if _, isModel := byName[field.Type]; isModel {
			sb.WriteString(fmt.Sprintf("  if (Array.isArray(%s))\n", key))
			sb.WriteString(fmt.Sprintf("    for (let _i = 0; _i < (%s as unknown[]).length; _i++)\n", key))
			sb.WriteString(fmt.Sprintf("      assert%s((%s as unknown[])[_i], `${path}.%s[${_i}]`);\n", field.Type, key, field.Name))
		}

	case field.IsMap:
		sb.WriteString(fmt.Sprintf("  if (%s && (typeof %s !== 'object' || Array.isArray(%s)))\n", present, key, key))
		sb.WriteString(fmt.Sprintf("    throw new VeldContractError(%s, 'Record | undefined', %s);\n", pathExpr, key))

	default:
		if _, isModel := byName[field.Type]; isModel {
			sb.WriteString(fmt.Sprintf("  if (%s)\n", present))
			sb.WriteString(fmt.Sprintf("    assert%s(%s, %s);\n", field.Type, key, pathExpr))
		} else if !enumNames[field.Type] {
			// Enums are string unions — skip runtime check (TS handles it at compile time).
			expected := tsScalarExpected(field.Type)
			sb.WriteString(fmt.Sprintf("  if (%s && typeof %s !== '%s')\n", present, key, expected))
			sb.WriteString(fmt.Sprintf("    throw new VeldContractError(%s, '%s | undefined', %s);\n", pathExpr, expected, key))
		}
	}
}

// ── assertXArray ──────────────────────────────────────────────────────────────

// writeNodeAssertArrayFunc generates an assertXArray() function for array outputs.
func writeNodeAssertArrayFunc(sb *strings.Builder, model ast.Model) {
	fnName := "assert" + model.Name + "Array"
	sb.WriteString(fmt.Sprintf("/** Asserts data is an array of %s. Throws VeldContractError (\u2192 500) on mismatch. */\n", model.Name))
	sb.WriteString(fmt.Sprintf("export function %s(data: unknown, path = '%s[]'): asserts data is Types.%s[] {\n", fnName, model.Name, model.Name))
	sb.WriteString("  if (!Array.isArray(data))\n")
	sb.WriteString("    throw new VeldContractError(path, 'array', data);\n")
	sb.WriteString("  for (let i = 0; i < data.length; i++)\n")
	sb.WriteString(fmt.Sprintf("    assert%s(data[i], `${path}[${i}]`);\n", model.Name))
	sb.WriteString("}\n")
}

// ── parseX ────────────────────────────────────────────────────────────────────

// writeNodeParseFunc generates a parseX() function that validates request input.
// Unlike assertX (which throws on first error), parseX collects all errors first
// for a better developer experience (shows all validation failures at once).
func writeNodeParseFunc(sb *strings.Builder, model ast.Model, byName map[string]ast.Model, enumNames map[string]bool) {
	fnName := "parse" + model.Name
	sb.WriteString(fmt.Sprintf("/** Parses and validates request input as %s. Throws VeldValidationError (\u2192 400) on failure. */\n", model.Name))
	sb.WriteString(fmt.Sprintf("export function %s(data: unknown): Types.%s {\n", fnName, model.Name))
	sb.WriteString("  if (data === null || typeof data !== 'object' || Array.isArray(data))\n")
	sb.WriteString("    throw new VeldValidationError(['request body must be a JSON object']);\n")
	sb.WriteString("  const d = data as Record<string, unknown>;\n")
	sb.WriteString("  const _errors: string[] = [];\n")

	// Include inherited fields so the input model is fully validated.
	// Skip @serverSet fields — those are set server-side, not by the client.
	allFields := collectAllFields(model, byName)
	for _, field := range allFields {
		if field.ServerSet {
			continue
		}
		writeNodeParseField(sb, field, byName, enumNames)
	}

	sb.WriteString("  if (_errors.length > 0) throw new VeldValidationError(_errors);\n")
	sb.WriteString(fmt.Sprintf("  return d as unknown as Types.%s;\n", model.Name))
	sb.WriteString("}\n")
}

// writeNodeParseField emits the per-field validation inside a parseX function.
func writeNodeParseField(sb *strings.Builder, field ast.Field, byName map[string]ast.Model, enumNames map[string]bool) {
	key := fmt.Sprintf("d['%s']", field.Name)

	if field.Optional {
		// Optional: only validate the type when the field is actually present.
		if len(field.UnionTypes) > 0 {
			// Union types — compile-time checked, no runtime validation needed for optional.
		} else if field.IsArray {
			sb.WriteString(fmt.Sprintf("  if (%s !== undefined && %s !== null && !Array.isArray(%s))\n", key, key, key))
			sb.WriteString(fmt.Sprintf("    _errors.push('%s: expected array');\n", field.Name))
		} else if field.IsMap {
			sb.WriteString(fmt.Sprintf("  if (%s !== undefined && %s !== null && (typeof %s !== 'object' || Array.isArray(%s)))\n", key, key, key, key))
			sb.WriteString(fmt.Sprintf("    _errors.push('%s: expected object (map)');\n", field.Name))
		} else if _, isModel := byName[field.Type]; isModel {
			sb.WriteString(fmt.Sprintf("  if (%s !== undefined && %s !== null && (typeof %s !== 'object' || Array.isArray(%s)))\n", key, key, key, key))
			sb.WriteString(fmt.Sprintf("    _errors.push('%s: expected object');\n", field.Name))
		} else if !enumNames[field.Type] {
			expected := tsScalarExpected(field.Type)
			sb.WriteString(fmt.Sprintf("  if (%s !== undefined && %s !== null && typeof %s !== '%s')\n", key, key, key, expected))
			sb.WriteString(fmt.Sprintf("    _errors.push('%s: expected %s');\n", field.Name, expected))
		}
	} else {
		// Required: field must be present and have the correct type.
		if len(field.UnionTypes) > 0 {
			// Union types — just check presence, TS handles the type check.
			sb.WriteString(fmt.Sprintf("  if (%s === undefined || %s === null)\n", key, key))
			sb.WriteString(fmt.Sprintf("    _errors.push('%s: required');\n", field.Name))
		} else if field.IsArray {
			sb.WriteString(fmt.Sprintf("  if (!Array.isArray(%s))\n", key))
			sb.WriteString(fmt.Sprintf("    _errors.push('%s: required array');\n", field.Name))
		} else if field.IsMap {
			sb.WriteString(fmt.Sprintf("  if (typeof %s !== 'object' || %s === null || Array.isArray(%s))\n", key, key, key))
			sb.WriteString(fmt.Sprintf("    _errors.push('%s: required object (map)');\n", field.Name))
		} else if _, isModel := byName[field.Type]; isModel {
			sb.WriteString(fmt.Sprintf("  if (typeof %s !== 'object' || %s === null || Array.isArray(%s))\n", key, key, key))
			sb.WriteString(fmt.Sprintf("    _errors.push('%s: required object');\n", field.Name))
		} else if enumNames[field.Type] {
			// Enums are string unions — check for string presence.
			sb.WriteString(fmt.Sprintf("  if (typeof %s !== 'string')\n", key))
			sb.WriteString(fmt.Sprintf("    _errors.push('%s: required string (enum %s)');\n", field.Name, field.Type))
		} else {
			expected := tsScalarExpected(field.Type)
			sb.WriteString(fmt.Sprintf("  if (typeof %s !== '%s')\n", key, expected))
			sb.WriteString(fmt.Sprintf("    _errors.push('%s: required %s');\n", field.Name, expected))
		}
	}
}

// ── Shared helpers ────────────────────────────────────────────────────────────

// topoSortModels returns models sorted so parents always precede children.
// Uses depth-first traversal of the extends chain.
func topoSortModels(models []ast.Model) []ast.Model {
	byName := modelsByName(models)
	visited := make(map[string]bool, len(models))
	result := make([]ast.Model, 0, len(models))

	var visit func(name string)
	visit = func(name string) {
		if visited[name] {
			return
		}
		visited[name] = true
		if m, ok := byName[name]; ok && m.Extends != "" {
			visit(m.Extends)
		}
		if m, ok := byName[name]; ok {
			result = append(result, m)
		}
	}

	// Visit in original order for deterministic output.
	for _, m := range models {
		visit(m.Name)
	}
	return result
}

// modelsByName builds a lookup map from model name to model.
func modelsByName(models []ast.Model) map[string]ast.Model {
	m := make(map[string]ast.Model, len(models))
	for _, model := range models {
		m[model.Name] = model
	}
	return m
}

// enumSet builds a set of all enum names for O(1) lookup.
func enumSet(enums []ast.Enum) map[string]bool {
	s := make(map[string]bool, len(enums))
	for _, e := range enums {
		s[e.Name] = true
	}
	return s
}

// collectArrayOutputModels returns a set of model names used as array outputs.
func collectArrayOutputModels(a ast.AST) map[string]bool {
	result := make(map[string]bool)
	for _, mod := range a.Modules {
		for _, act := range mod.Actions {
			if act.Output != "" && act.OutputArray {
				result[act.Output] = true
			}
		}
	}
	return result
}

// collectInputModels returns a set of model names used as action inputs.
func collectInputModels(a ast.AST) map[string]bool {
	result := make(map[string]bool)
	for _, mod := range a.Modules {
		for _, act := range mod.Actions {
			if act.Input != "" {
				result[act.Input] = true
			}
		}
	}
	return result
}

// collectAllFields returns all fields for a model including inherited fields,
// walking the extends chain recursively. Parent fields come first.
func collectAllFields(model ast.Model, byName map[string]ast.Model) []ast.Field {
	var fields []ast.Field
	if model.Extends != "" {
		if parent, ok := byName[model.Extends]; ok {
			fields = append(fields, collectAllFields(parent, byName)...)
		}
	}
	return append(fields, model.Fields...)
}

// tsScalarExpected maps a Veld scalar type to the TypeScript typeof string.
func tsScalarExpected(veldType string) string {
	switch veldType {
	case "string", "date", "datetime", "uuid":
		return "string"
	case "int", "float":
		return "number"
	case "bool":
		return "boolean"
	default:
		return "string" // enums and unknown types default to string
	}
}

// buildValidatorImports collects the validator function names needed by a module's routes.
// Returns a sorted slice for deterministic output.
func buildValidatorImports(mod ast.Module) []string {
	seen := make(map[string]bool)
	for _, act := range mod.Actions {
		if act.Method == "WS" {
			continue
		}
		if act.Input != "" {
			seen["parse"+act.Input] = true
		}
		if act.Output != "" && !(act.Method == "DELETE" && act.Output == "") {
			if act.OutputArray {
				seen["assert"+act.Output+"Array"] = true
			} else {
				seen["assert"+act.Output] = true
			}
		}
	}

	imports := make([]string, 0, len(seen))
	for name := range seen {
		imports = append(imports, name)
	}
	sort.Strings(imports) // deterministic output
	return imports
}
